// Utility to create a canonical bridge key from two islands
// Key format: "x1,y1,x2,y2" where (x1,y1) sorts before (x2,y2)
export function makeBridgeKey(a, b) {
  if (a.x < b.x || (a.x === b.x && a.y < b.y)) {
    return `${a.x},${a.y},${b.x},${b.y}`;
  }
  return `${b.x},${b.y},${a.x},${a.y}`;
}

// Check if two islands are on the same row or column (adjacent axis)
function areAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

// Check if there's any island between a and b on the same line
function hasIslandBetween(islands, a, b) {
  if (a.x === b.x) {
    // vertical
    const minY = Math.min(a.y, b.y);
    const maxY = Math.max(a.y, b.y);
    return islands.some(isl =>
      isl.id !== a.id && isl.id !== b.id &&
      isl.x === a.x && isl.y > minY && isl.y < maxY
    );
  } else if (a.y === b.y) {
    // horizontal
    const minX = Math.min(a.x, b.x);
    const maxX = Math.max(a.x, b.x);
    return islands.some(isl =>
      isl.id !== a.id && isl.id !== b.id &&
      isl.y === a.y && isl.x > minX && isl.x < maxX
    );
  }
  return false;
}

// Check if two line segments cross (not just touch)
function segmentsCross(ax1, ay1, ax2, ay2, bx1, by1, bx2, by2) {
  // Only check perpendicular segments (one horizontal, one vertical)
  const aHoriz = ay1 === ay2;
  const aVert = ax1 === ax2;
  const bHoriz = by1 === by2;
  const bVert = bx1 === bx2;

  if (aHoriz && bVert) {
    const aMinX = Math.min(ax1, ax2);
    const aMaxX = Math.max(ax1, ax2);
    const bMinY = Math.min(by1, by2);
    const bMaxY = Math.max(by1, by2);
    // Strictly between (not at endpoints)
    return bx1 > aMinX && bx1 < aMaxX && ay1 > bMinY && ay1 < bMaxY;
  }

  if (aVert && bHoriz) {
    const bMinX = Math.min(bx1, bx2);
    const bMaxX = Math.max(bx1, bx2);
    const aMinY = Math.min(ay1, ay2);
    const aMaxY = Math.max(ay1, ay2);
    return ax1 > bMinX && ax1 < bMaxX && by1 > aMinY && by1 < aMaxY;
  }

  // Parallel segments don't cross in Hashi
  return false;
}

// Check if adding a bridge between from and to would cross any existing bridge
function wouldCross(islands, bridges, from, to) {
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [ex1, ey1, ex2, ey2] = parts;
    if (segmentsCross(from.x, from.y, to.x, to.y, ex1, ey1, ex2, ey2)) {
      return true;
    }
  }
  return false;
}

// Compute the current bridge count for each island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) {
    counts.set(isl.id, 0);
  }
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;
    // Find islands at these positions
    const islA = islands.find(i => i.x === x1 && i.y === y1);
    const islB = islands.find(i => i.x === x2 && i.y === y2);
    if (islA) counts.set(islA.id, (counts.get(islA.id) || 0) + count);
    if (islB) counts.set(islB.id, (counts.get(islB.id) || 0) + count);
  }
  return counts;
}

// Check if adding delta bridges between from and to is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Same island
  if (from.id === to.id) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  // Not aligned (not on same row or column)
  if (!areAligned(from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  // Island between them
  if (hasIslandBetween(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = makeBridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Max 2 bridges
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value) {
    return { valid: false, error: "Island would exceed its number" };
  }
  if (toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing
  if (delta > 0 && current === 0) {
    // Only check crossing when creating a new bridge (not adding to existing)
    if (wouldCross(islands, bridges, from, to)) {
      return { valid: false, error: "Bridges would cross" };
    }
  }

  return { valid: true, error: null };
}

// Check connectivity: all islands with at least one bridge are connected
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  // Build adjacency list based on bridges
  const adj = new Map();
  for (const isl of islands) {
    adj.set(isl.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;
    const islA = islands.find(i => i.x === x1 && i.y === y1);
    const islB = islands.find(i => i.x === x2 && i.y === y2);
    if (islA && islB) {
      adj.get(islA.id).push(islB.id);
      adj.get(islB.id).push(islA.id);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const curr = queue.shift();
    for (const neighbor of adj.get(curr)) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check if the puzzle is solved
export function isVictory(islands, bridges) {
  // Check all island counts match their values
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) || 0) !== isl.value) {
      return false;
    }
  }

  // Check no bridges cross
  const bridgeSegments = [];
  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    bridgeSegments.push(parts);
  }
  for (let i = 0; i < bridgeSegments.length; i++) {
    for (let j = i + 1; j < bridgeSegments.length; j++) {
      const [ax1, ay1, ax2, ay2] = bridgeSegments[i];
      const [bx1, by1, bx2, by2] = bridgeSegments[j];
      if (segmentsCross(ax1, ay1, ax2, ay2, bx1, by1, bx2, by2)) {
        return false;
      }
    }
  }

  // Check connectivity
  return checkConnectivity(islands, bridges);
}
