  const adj = new Map();
  for (const isl of islands) {
    adj.set(isl.id, []);
  }

  for (const [key, count] of bridges) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const [x1, y1, x2, y2] = parts;
    const islA = islands.find(i => i.x === x1 && i.y === y1);
    const islB = islands.find(i => i.x === x2 && i.y === y2);
    if (islA && islB) {
      adj.get(islA.id).push(islB.id);
      adj.get(islB.id).push(islA.id);
