            key={key}
            x1={px1}
            y1={py1}
            x2={px2}
            y2={py2}
            stroke="#0f0"
            strokeWidth="3"
            style={{ cursor: 'pointer' }}
            onContextMenu={handleContext}
            onClick={handleClick}
          />
