            x1={px1 + dx}
            y1={py1 + dy}
            x2={px2 + dx}
            y2={py2 + dy}
            stroke="#0f0"
            strokeWidth="3"
            style={{ cursor: 'pointer' }}
            onContextMenu={handleContext}
            onClick={handleClick}
          />
        );
      }
    }
